 * SIGCHLD simple avec un seul enfant
 * ================================================= */
volatile sig_atomic_t ex_done = 0;
void ex_handler(int s) { (void)s; wait(NULL); ex_done = 1; }
void example_sigchld(void) {
    struct sigaction sa = {.sa_handler = ex_handler, .sa_flags = SA_RESTART};
    sigemptyset(&sa.sa_mask);
    sigaction(SIGCHLD, &sa, NULL);
    if (fork() == 0) _exit(0);
    while (!ex_done) usleep(1000);
    printf("example: child reaped\n");
}

